import { execSync } from "child_process";
import fs from "fs";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const F={"main": "", "profile": "", "profilejs": ""};const E2E="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){\n  if(($_GET['ps_e2e']??'')!=='1')return;\n  if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;\n  global $wpdb;\n  $out=array();\n  $out['0_ver']=defined('PETSHOP_CORE_VERSION')?PETSHOP_CORE_VERSION:'?';\n\n  // Ar client_ref stulpelis yra?\n  $cols=$wpdb->get_col(\"DESC {$wpdb->prefix}ps_pets\");\n  $out['0_client_ref_col']=in_array('client_ref',$cols)?'YRA':'NERA';\n\n  $testmail='e2e_'.time().'@gyvunai.lt';\n\n  // === SCENARIJUS 1: Naujas el. pa\u0161tas, nauja paskyra, profilis persikelia ===\n  // Simuliuojam: anoniminis sukure juodrasti (draft_id=D1), prisijunge, transfer POST su client_ref\n  $uid1=wp_create_user('e2e_new_'.time(), wp_generate_password(), $testmail);\n  wp_set_current_user($uid1);\n  $req=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req->set_param('species','dog');$req->set_param('pet_name','Reksas');$req->set_param('primary_need','skin_allergy');\n  $req->set_param('client_ref','D1abc123');\n  $r=rest_do_request($req)->get_data();\n  $out['1_new_account']=array('pet_id'=>$r['pet_id']??null,'ok'=>$r['ok']??false);\n  $petcount=$wpdb->get_var($wpdb->prepare(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_pets WHERE user_id=%d AND status='active'\",$uid1));\n  $out['1_pet_saved']=($petcount==1)?'OK (1 pet DB)':'BLOGAI ('.$petcount.')';\n\n  // === SCENARIJUS 9: Pakartotinis magic link \u2014 tas pats client_ref NEKURIA dublikato ===\n  $req2=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req2->set_param('species','dog');$req2->set_param('pet_name','Reksas');$req2->set_param('primary_need','skin_allergy');\n  $req2->set_param('client_ref','D1abc123'); // TAS PATS\n  $r2=rest_do_request($req2)->get_data();\n  $out['9_repeat_magic_link']=array('pet_id'=>$r2['pet_id']??null,'dedup'=>$r2['deduplicated']??false);\n  $petcount2=$wpdb->get_var($wpdb->prepare(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_pets WHERE user_id=%d AND status='active'\",$uid1));\n  $out['9_no_duplicate']=($petcount2==1 && ($r2['pet_id']??0)==($r['pet_id']??-1))?'OK (dedup, 1 pet)':'BLOGAI ('.$petcount2.' pets)';\n\n  // === SCENARIJUS 2: Esama paskyra be augintiniu ===\n  $uid2=wp_create_user('e2e_empty_'.time(), wp_generate_password(), 'e2e_empty_'.time().'@gyvunai.lt');\n  wp_set_current_user($uid2);\n  // Vartotojas jau turi paskyra bet 0 pets, transferina juodrasti\n  $req3=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req3->set_param('species','cat');$req3->set_param('pet_name','Murk\u0117');$req3->set_param('client_ref','D2xyz');\n  $r3=rest_do_request($req3)->get_data();\n  $out['2_existing_empty']=($r3['ok']??false)?'OK (pet_id '.$r3['pet_id'].', is_primary='.($r3['is_primary']?'yes':'no').')':'BLOGAI';\n\n  // === SCENARIJUS 3: Esama paskyra su KITU augintiniu ===\n  // uid2 jau turi Murke, dabar transferina Reksa\n  $req4=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req4->set_param('species','dog');$req4->set_param('pet_name','Reksas');$req4->set_param('client_ref','D3new');\n  $r4=rest_do_request($req4)->get_data();\n  $petcount3=$wpdb->get_var($wpdb->prepare(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_pets WHERE user_id=%d AND status='active'\",$uid2));\n  $out['3_existing_other_pet']=($petcount3==2)?'OK (2 pets: Murke+Reksas)':'BLOGAI ('.$petcount3.')';\n  $out['3_second_not_primary']=($r4['is_primary']??true)?'BLOGAI (turi but ne primary)':'OK (ne primary)';\n\n  // === SCENARIJUS 4: Galimas dublikatas \u2014 ta pati rusis IR vardas, KITAS client_ref ===\n  // Konsultantas: neturi auto-merge. Turi sukurt atskira (arba parodyt vartotojui). MVP: kuriam atskira.\n  $req5=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req5->set_param('species','dog');$req5->set_param('pet_name','Reksas');$req5->set_param('client_ref','D4dup');\n  $r5=rest_do_request($req5)->get_data();\n  $petcount4=$wpdb->get_var($wpdb->prepare(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_pets WHERE user_id=%d AND status='active'\",$uid2));\n  $out['4_duplicate_pet']=array('created'=>$r5['ok']??false,'total_pets'=>$petcount4,'note'=>'KITAS client_ref -> kuriam atskira (ne auto-merge). Vartotojas mato abu, gali istrint.');\n\n  // === Cleanup ===\n  require_once ABSPATH.'wp-admin/includes/user.php';\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id IN (%d,%d)\",$uid1,$uid2));\n  wp_delete_user($uid1);wp_delete_user($uid2);\n  $out['cleanup']='done';\n\n  header('Content-Type: application/json; charset=utf-8');\n  echo wp_json_encode($out, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT);\n  exit;\n},6);";
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'');}return r;}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
(async()=>{
  let out='';const L=s=>{out+=s+'\n';};
  const depPHP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_ed']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;$d=WP_PLUGIN_DIR.'/petshop-core';$o=array();$o['profile']=@file_put_contents($d.'/includes/class-pet-profile.php',base64_decode('"+F.profile+"'));$o['pjs']=@file_put_contents($d.'/assets/pet-profile.js',base64_decode('"+F.profilejs+"'));$o['main']=@file_put_contents($d.'/petshop-core.php',base64_decode('"+F.main+"'));header('Content-Type:application/json');echo wp_json_encode($o);exit;},6);";
  const c=api('POST','/wp-json/code-snippets/v1/snippets',{name:'E2EDep',desc:'x',code:depPHP,scope:'global',active:true,priority:5});
  let sid=0;try{sid=JSON.parse(c).id;}catch(e){}
  execSync('sleep 2');
  L('deploy: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_ed=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid) api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  // Reactivate (schema keitesi — client_ref stulpelis per ensure_columns activation)
  const actPHP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_ea']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;if(!function_exists('activate_plugin'))require_once ABSPATH.'wp-admin/includes/plugin.php';deactivate_plugins('petshop-core/petshop-core.php');$e=activate_plugin('petshop-core/petshop-core.php');header('Content-Type:application/json');echo wp_json_encode(array('active'=>is_plugin_active('petshop-core/petshop-core.php'),'err'=>is_wp_error($e)?$e->get_error_message():null,'ver'=>defined('PETSHOP_CORE_VERSION')?PETSHOP_CORE_VERSION:'?'));exit;},6);";
  const c2=api('POST','/wp-json/code-snippets/v1/snippets',{name:'E2EAct',desc:'x',code:actPHP,scope:'global',active:true,priority:5});
  let sid2=0;try{sid2=JSON.parse(c2).id;}catch(e){}
  execSync('sleep 2');
  L('reactivate: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_ea=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid2) api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});
  L('Home: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 -o /dev/null -w "HTTP:%{http_code}" "'+BASE+'/?nc='+Date.now()+'"'));

  const c3=api('POST','/wp-json/code-snippets/v1/snippets',{name:'E2ETest',desc:'x',code:E2E,scope:'global',active:true,priority:10});
  let sid3=0;try{sid3=JSON.parse(c3).id;}catch(e){}
  execSync('sleep 2');
  L(''); L('=== ANONIMINIO KELIO E2E ==='); L(sh('curl -s -k -A "Mozilla/5.0" --max-time 60 "'+BASE+'/?ps_e2e=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid3) api('POST','/wp-json/code-snippets/v1/snippets/'+sid3+'/deactivate',{});
  putText('e2e_test.txt',out);
})();
